// ============================================================
// CredentialsService v2 ? Validation
// ============================================================

const items = $input.all();

const VALID_ACTIONS = [
  'GET_CREDENTIAL',
  'VALIDATE_CREDENTIAL',
  'UPDATE_TOKEN',
  'CHECK_EXPIRATION',
];

return items.map((it, idx) => {
  const input = it.json || {};
  const action = String(input.action || '').trim().toUpperCase();

  if (!action) {
    throw new Error(`CredentialsService ? [item ${idx}] champ obligatoire manquant: action`);
  }
  if (!VALID_ACTIONS.includes(action)) {
    throw new Error(`CredentialsService ? [item ${idx}] action inconnue: '${action}'. Valides: ${VALID_ACTIONS.join(', ')}`);
  }

  if (input.tenant_id === undefined || input.tenant_id === null || String(input.tenant_id).trim() === '') {
    throw new Error(`CredentialsService ? [item ${idx}] champ obligatoire manquant: tenant_id`);
  }

  if (action === 'GET_CREDENTIAL' || action === 'VALIDATE_CREDENTIAL' || action === 'CHECK_EXPIRATION') {
    if (!input.credential_ref) {
      throw new Error(`CredentialsService ${action} ? [item ${idx}] champ obligatoire manquant: credential_ref`);
    }
  }

  if (action === 'UPDATE_TOKEN') {
    const missing = [];
    if (!input.credential_ref) missing.push('credential_ref');
    if (!input.new_access_token) missing.push('new_access_token');
    if (!input.new_expires_at) missing.push('new_expires_at');
    if (missing.length) {
      throw new Error(`CredentialsService UPDATE_TOKEN ? [item ${idx}] champs manquants: ${missing.join(', ')}`);
    }
  }

  return {
    json: {
      ...input,
      action,
      __req_idx: idx,
    },
    pairedItem: it.pairedItem ?? { item: idx },
  };
});

// ============================================================
// Réponse GET_CREDENTIAL v2 (PostgreSQL)
// ============================================================
// SIMPLIFICATION vs v1 :
//   - Plus besoin de rec.fields vs rec (PostgreSQL retourne plat)
//   - Plus de airtable_record_id
//   - Requête paramétrisée = anti injection SQL
// ============================================================

const results = $input.all();
const allReq = $items('Valider entrée & action').map(i => i.json);
const reqs = allReq.filter(r => r.action === 'GET_CREDENTIAL');

return reqs.map((rq, subIdx) => {
  const row = results[subIdx]?.json?.data?.data || null;

  if (!row) {
    return {
      json: {
        success: false,
        action: 'GET_CREDENTIAL',
        error_code: 'CREDENTIAL_NOT_FOUND',
        error_message: `credential_ref '${rq.credential_ref}' introuvable dans le Credentials Store`,
      },
      pairedItem: { item: rq.__req_idx },
    };
  }

  return {
    json: {
      success: true,
      action: 'GET_CREDENTIAL',
      credential: {
        credential_ref: rq.credential_ref,
        client_id: row.client_id ?? null,
        platform: row.platform || '',
        access_token: row.access_token || '',
        refresh_token: row.refresh_token || '',
        client_app_id: row.client_app_id || '',
        client_secret: row.client_secret || '',
        expires_at: row.expires_at || null,
      },
    },
    pairedItem: { item: rq.__req_idx },
  };
});

// ============================================================
// Réponse VALIDATE_CREDENTIAL v2 (PostgreSQL)
// ============================================================
// Logique métier IDENTIQUE à v1 :
//   - Vérifie l'existence
//   - Vérifie la compatibilité platform ↔ channel_name
//   - Conserve le contexte entrant (...rq)
// ============================================================

const results = $input.all();
const allReq = $items('Valider entrée & action').map((it, idx) => ({
  __req_idx: idx,
  ...it.json
}));
const reqs = allReq.filter(r => r.action === 'VALIDATE_CREDENTIAL');

const CHANNEL_TO_PLATFORM = {
  FACEBOOK: 'facebook',
  INSTAGRAM: 'facebook',
  LINKEDIN: 'linkedin',
};

return reqs.map((rq, subIdx) => {
  const row = results[subIdx]?.json?.data?.data || null;

  // Credential introuvable
  if (!row) {
    return {
      json: {
        ...rq,
        success: true,
        action: 'VALIDATE_CREDENTIAL',
        credential_ref: rq.credential_ref,
        exists: false,
        valid: false,
        error_code: 'CREDENTIAL_NOT_FOUND',
        error_message: `credential_ref '${rq.credential_ref}' introuvable`,
      },
      pairedItem: { item: rq.__req_idx },
    };
  }

  const platform = String(row.platform || '').toLowerCase();

  // Vérification compatibilité channel ↔ platform
  if (rq.channel_name) {
    const channelNorm = String(rq.channel_name).trim().toUpperCase();
    const expected = CHANNEL_TO_PLATFORM[channelNorm];

    if (!expected) {
      return {
        json: {
          ...rq,
          success: true,
          action: 'VALIDATE_CREDENTIAL',
          credential_ref: rq.credential_ref,
          exists: true,
          valid: false,
          error_code: 'UNSUPPORTED_CHANNEL',
          error_message: `Canal '${channelNorm}' non supporté`,
        },
        pairedItem: { item: rq.__req_idx },
      };
    }

    const isMatch =
      platform === expected ||
      (platform === 'facebook' &&
        (channelNorm === 'FACEBOOK' || channelNorm === 'INSTAGRAM'));

    if (!isMatch) {
      return {
        json: {
          ...rq,
          success: true,
          action: 'VALIDATE_CREDENTIAL',
          credential_ref: rq.credential_ref,
          exists: true,
          valid: false,
          platform_actual: platform,
          channel_expected: channelNorm,
          error_code: 'CREDENTIAL_PLATFORM_MISMATCH',
          error_message: `credential_ref pointe vers '${platform}', attendu plateforme compatible avec '${channelNorm}'`,
        },
        pairedItem: { item: rq.__req_idx },
      };
    }
  }

  return {
    json: {
      ...rq,
      success: true,
      action: 'VALIDATE_CREDENTIAL',
      credential_ref: rq.credential_ref,
      exists: true,
      valid: true,
      platform,
      client_id: row.client_id ?? null,
      error_code: null,
      error_message: null,
    },
    pairedItem: { item: rq.__req_idx },
  };
});

// ============================================================
// Reponse UPDATE_TOKEN v2 (Vault KV v2)
// ============================================================

const results = $input.all();
const allReq = $items('Valider entree & action').map(i => i.json);
const reqs = allReq.filter(r => r.action === 'UPDATE_TOKEN');

return reqs.map((rq, subIdx) => {
  const row = results[subIdx]?.json || {};

  const ok = !!(row?.data?.version || row?.data?.created_time || Object.keys(row).length > 0);

  if (!ok) {
    return {
      json: {
        success: false,
        action: 'UPDATE_TOKEN',
        credential_ref: rq.credential_ref,
        error_code: 'VAULT_WRITE_FAILED',
        error_message: `Echec ecriture Vault pour credential_ref '${rq.credential_ref}'`,
      },
      pairedItem: { item: rq.__req_idx },
    };
  }

  return {
    json: {
      success: true,
      action: 'UPDATE_TOKEN',
      credential_ref: rq.credential_ref,
      new_expires_at: rq.new_expires_at || null,
      refresh_token_updated: !!rq.new_refresh_token,
      version: row?.data?.version || null,
    },
    pairedItem: { item: rq.__req_idx },
  };
});

// ============================================================
// Réponse CHECK_EXPIRATION v2 (PostgreSQL)
// ============================================================
// Logique métier IDENTIQUE à v1 :
//   - Calcule si le token est expiré
//   - Calcule expires_in_seconds
//   - Détermine si un refresh est nécessaire (< 5 min)
// BONUS PostgreSQL :
//   - has_refresh_token calculé directement en SQL
//     (pas besoin de vérifier !!f.refresh_token en JS)
// ============================================================

const results = $input.all();
const allReq = $items('Valider entrée & action').map(i => i.json);
const reqs = allReq.filter(r => r.action === 'CHECK_EXPIRATION');

return reqs.map((rq, subIdx) => {
  const row = results[subIdx]?.json?.data?.data || null;

  if (!row) {
    return {
      json: {
        success: false,
        action: 'CHECK_EXPIRATION',
        error_code: 'CREDENTIAL_NOT_FOUND',
        error_message: `credential_ref '${rq.credential_ref}' introuvable`,
      },
      pairedItem: { item: rq.__req_idx },
    };
  }

  const now = new Date();
  const expiresAt = row.expires_at ? new Date(row.expires_at) : null;

  let expired = true;
  let expires_in_seconds = 0;
  let needs_refresh = true;

  if (expiresAt) {
    expired = expiresAt <= now;
    expires_in_seconds = Math.floor((expiresAt - now) / 1000);
    needs_refresh = expires_in_seconds < 300; // < 5 minutes
  }

  return {
    json: {
      success: true,
      action: 'CHECK_EXPIRATION',
      credential_ref: rq.credential_ref,
      platform: row.platform || '',
      expires_at: row.expires_at || null,
      expired,
      expires_in_seconds: Math.max(0, expires_in_seconds),
      needs_refresh,
      has_refresh_token: !!row.refresh_token,
    },
    pairedItem: { item: rq.__req_idx },
  };
});
